                new Kitap { Id = 56, Ad = "Fatih Sultan Mehmed", Yazar = "İlber Ortaylı", Yayinevi = "Kronik Kitap", Fiyat = 255.00 , ResimYolu = "/img/kitap/tarih/fatih.jpg", Kategori = "Tarih" , Aciklama = "Fâtih, Avrupa’dan Karadeniz’e kadar ömrü sefer-i hümâyunda geçen bir hükümdardı. Devrin yazarları onu Büyük İskender, Hannibal ve Caesar’la karşılaştırıyordu. Aynı zamanda, ülkesine İtalya’dan ressamlar getirecek kadar sanatla da ilgiliydi. Arapça, Farsça, İtalyanca ve Yunanca biliyordu. İmparatorluğunu ve çevresindeki dünyayı tarihiyle ve coğrafyasıyla tanımak istiyordu. Fâtih Sultan Mehmed’i tek bir cümleyle ifade etmek gerekirse: Doğu’nun ve Batı’nın efendisiydi. -İlber Ortaylı" , SayfaSayisi  = 448 , BasimYili = "2025"  },
                new Kitap { Id = 58, Ad = "Türklerin Tarihi", Yazar = "İlber Ortaylı", Yayinevi = "Kronik Kitap", Fiyat = 207.00 , ResimYolu = "/img/kitap/tarih/turklerin.jpg", Kategori = "Tarih" , Aciklama = "Türklerin Tarihi, göçebe bir kavimken Ortadoğu’nun güçlü uygarlıklarından birini tesis eden Türklerin günümüzde de çok konuşulan menşei tartışmalarıyla başlıyor. Akabinde Orta Asya’dan Anadolu’ya göç edip bölgeyi Türkleştirmeleri ve orada inşa ettikleri kültürün esasları… Büyük bir mirasa, güçlü bir yapılanmaya ve tarihî bir zenginliğe sahip bir milletin, Türklerin adının nereden geldiği ve bu coğrafyaya ne zamandan beri “Türkiye” dendiği tartışmalarının tüm detayları… " , SayfaSayisi  = 272 , BasimYili = "2022"  },
