                new Kitap { Id = 61, Ad = "Sultanı Öldürmek", Yazar = "Ahmet Ümit", Yayinevi = "Yapı Kredi Yayınları", Fiyat =357.50  , ResimYolu = "/img/kitap/tarih/sultan.jpg", Kategori = "Tarih" , Aciklama = "Sultanı Öldürmek, günümüzde geçen ve postmodern bir anlatıdan izler taşıyan diliyle hayli sürükleyici, zengin bir roman. Ahmet Ümit bu sefer Osmanlı’nın artık bir imparatorluğa dönüştüğü, zaferlerle birlikte daha cazip gelen iktidarı elde etmek için ihanet ve entrikaların yaygınlaştığı bir dönemi hikâyesine fon olarak seçiyor. Geçmişin ve günümüzün katilleri kurguda iç içe geçiyor. Biri sizi cinayet işlemekle suçladığında deliller bulur, tanıklar gösterir, bunun bir iftira olduğunu kanıtlamaya çalışırsınız ama sizi itham eden kişi bizzat kendinizseniz, ne yaparsınız?* " , SayfaSayisi  = 584 , BasimYili = "2023"  },
                new Kitap { Id = 62, Ad = "Çankaya", Yazar = "Falih Rıfkı Atay", Yayinevi = "Pozitif Yayınları", Fiyat = 397.50 , ResimYolu = "/img/kitap/tarih/cankaya.jpg", Kategori = "Tarih" , Aciklama = "Falih Rıfkı Atay, 1923’den 1938’e kadar Atatürk’ün yanında bulunmuş, O’nun yaşadıklarını bizzat kendisinden dinlemiş ve hatta birçoğuna şahit olmuş devrin önemli gazetecilerindendir. Çankaya, Atatürk’ü doğumundan okul yıllarına, savaştığı cephelerden yaptığı inkılaplara, tartışma sofralarından insani yönlerine kadar her detayı anektodlara yer vererek anlatan muazzam bir kitaptır. " , SayfaSayisi  = 596 , BasimYili = "2024"  },
