        public IActionResult Index(string searchString)
        {
            try
            {
                var tumUrunler = GetUrunler();

                if (!string.IsNullOrEmpty(searchString))
                {
                    var sonuc = tumUrunler.Where(k =>
    (k.Ad != null && k.Ad.Contains(searchString, StringComparison.OrdinalIgnoreCase)) ||
    (k is Kitap kitap && (
        (kitap.Yazar != null && kitap.Yazar.Contains(searchString, StringComparison.OrdinalIgnoreCase)) ||
        (kitap.Yayinevi != null && kitap.Yayinevi.Contains(searchString, StringComparison.OrdinalIgnoreCase))
    )) ||
    (k is Puzzle puzzle && (
        (puzzle.Marka != null && puzzle.Marka.Contains(searchString, StringComparison.OrdinalIgnoreCase))
    ))
).ToList();

                    return View(sonuc);
                }

                var sadeceKitaplar = tumUrunler.Where(k => !k.Kategori.Contains("Puzzle")).ToList();
                return View(sadeceKitaplar);
            }
            catch (Exception ex)
            {
                return View(new List<Urun>());
            }
        }

        public IActionResult Iletisim(IletisimMesaj gelenMesaj)
        {
            if (ModelState.IsValid)
            {
                Console.WriteLine($"Yeni Mesaj: {gelenMesaj.Ad} {gelenMesaj.Soyad} | Konu: {gelenMesaj.Konu} | İçerik: {gelenMesaj.Mesaj}");

                return RedirectToAction("Index");
            }
            return View(gelenMesaj);
        }

        private readonly UrunServisi _urunServisi;

        public HomeController(UrunServisi urunServisi)
        {
            _urunServisi = urunServisi;
        }

        [HttpPost]
        public IActionResult FavoriGuncelle(int id)
        {
            _urunServisi.FavoriEkleCikar(id);
            return RedirectToAction("Index");
        }

        public IActionResult Favorilerim()
        {
            var favoriIdler = _urunServisi.FavorileriGetir();

            var favoriUrunler = GetUrunler().Where(u => favoriIdler.Contains(u.Id)).ToList();

            ViewData["Title"] = "Favorilerim";
            return View(favoriUrunler);
        }

        public IActionResult Satis()
        {
            ViewData["Title"] = "Satış Sözleşmesi";
            return View();
        }

        public IActionResult Hakkimizda()
        {
            ViewData["Title"] = "Hakkımızda";
            return View();
        }

        public IActionResult Yayinevleri()
        {
            ViewData["Title"] = "Yayınevleri";
            return View();
        }

        public IActionResult Detay(int id)
        {
            try
            {
                var kitap = GetUrunler().First(k => k.Id == id);
                return View(kitap);
            }
            catch (InvalidOperationException)
            {
                return RedirectToAction("Index");
            }
            catch (Exception ex)
            {
                Console.WriteLine("Hata oluştu: " + ex.Message);
                return View("Error");
            }
        }

        public IActionResult Kategori(string id)
        {
            var tumKitaplar = GetUrunler();
            var filtrelenenler = tumKitaplar.Where(k => k.Kategori.Contains(id)).ToList();

            if (!filtrelenenler.Any())
            {
                return RedirectToAction("Index");
            }
            string sayfaBasligi;
            if (id == "Cocuk")
            {
                sayfaBasligi = "Çocuk Kitapları";
            }
            else if (id == "500")
            {
                sayfaBasligi = "500 Parçalı Puzzle";
            }
            else if (id == "2000")
            {
                sayfaBasligi = "2000 Parçalı Puzzle";
            }
            else if (id == "1000")
            {
                sayfaBasligi = "1000 Parçalı Puzzle";
            }
            else if (id == "3000")
            {
                sayfaBasligi = "3000 Parçalı Puzzle";
            }
            else if (id.Contains("Puzzle"))
            {
                sayfaBasligi = "Puzzle";
            }
            else
            {
                sayfaBasligi = id + " Kitapları";
            }
            ViewData["Title"] = sayfaBasligi;
            return View("Index", filtrelenenler);
        }
    }
}